	switch status {
	case "implementing":
		return ColorIris
	case "planning", "running":
		return ColorFoam
	case "reviewing", "done":
		return ColorGold
	case "ready", "cancelled", "paused":
		return ColorMuted
	case "failed", "error":
		return ColorLove
	default:
		return ColorText
	}
}

// renderRow renders a single label+value row.
