		Foreground(ColorFoam).
		Border(lipgloss.RoundedBorder()).
		BorderForeground(ColorOverlay).
		Padding(0, 2)
	rows = append(rows, "")
	rows = append(rows, zone.Mark(ZoneViewPlan, btnStyle.Render("view plan doc")))

	return strings.Join(rows, "\n")
